import{_ as t,o as r,c as a,a6 as d}from"./chunks/framework.B6HGZFrS.js";const p=JSON.parse('{"title":"Architecture and Layering","description":"","frontmatter":{},"headers":[],"relativePath":"agent-instructions/architecture.md","filePath":"agent-instructions/architecture.md","lastUpdated":1780302832000}'),o={name:"agent-instructions/architecture.md"};function i(c,e,s,l,n,h){return r(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="architecture-and-layering" tabindex="-1">Architecture and Layering <a class="header-anchor" href="#architecture-and-layering" aria-label="Permalink to “Architecture and Layering”">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to “Overview”">​</a></h2><p>Use this file when adding or changing API behavior, moving code between layers, or checking whether a change belongs in a service, controller, route, utility, or type module.</p><h2 id="project-shape" tabindex="-1">Project Shape <a class="header-anchor" href="#project-shape" aria-label="Permalink to “Project Shape”">​</a></h2><table tabindex="0"><thead><tr><th>Path</th><th>Role</th></tr></thead><tbody><tr><td><code>src/app.ts</code></td><td>Application startup entry</td></tr><tr><td><code>src/index.ts</code></td><td>Package export entry</td></tr><tr><td><code>src/koaApp.ts</code></td><td>Koa app composition</td></tr><tr><td><code>src/services/</code></td><td>QQ Music upstream request and API capability layer</td></tr><tr><td><code>src/controllers/</code></td><td>HTTP controller layer</td></tr><tr><td><code>src/routes/</code></td><td>Route registration and API metadata</td></tr><tr><td><code>src/middlewares/</code></td><td>Koa middleware</td></tr><tr><td><code>src/util/</code></td><td>Shared utility helpers</td></tr><tr><td><code>src/config/</code></td><td>Runtime configuration</td></tr><tr><td><code>src/types/</code></td><td>Shared and global TypeScript types</td></tr><tr><td><code>docs/</code></td><td>VitePress documentation</td></tr><tr><td><code>tests/</code></td><td>Unit and integration tests</td></tr><tr><td><code>public/</code></td><td>Static assets</td></tr><tr><td><code>scripts/</code></td><td>Maintenance and build scripts</td></tr></tbody></table><h2 id="layer-rules" tabindex="-1">Layer Rules <a class="header-anchor" href="#layer-rules" aria-label="Permalink to “Layer Rules”">​</a></h2><h3 id="src-services" tabindex="-1"><code>src/services/</code> <a class="header-anchor" href="#src-services" aria-label="Permalink to “src/services/”">​</a></h3><ul><li>Build upstream QQ Music request parameters.</li><li>Call upstream APIs.</li><li>Perform basic response conversion.</li><li>Return the project&#39;s unified response structures.</li><li>Do not read or mutate Koa <code>ctx</code>, set HTTP status, or own route-level validation.</li></ul><h3 id="src-controllers" tabindex="-1"><code>src/controllers/</code> <a class="header-anchor" href="#src-controllers" aria-label="Permalink to “src/controllers/”">​</a></h3><ul><li>Read <code>ctx.query</code> or <code>ctx.request.body</code>.</li><li>Validate request parameters for the HTTP surface.</li><li>Call the corresponding service function.</li><li>Set <code>ctx.body</code> and <code>ctx.status</code>.</li><li>Do not inline upstream request details that belong in <code>src/services/</code>.</li></ul><h3 id="src-routes-router-ts" tabindex="-1"><code>src/routes/router.ts</code> <a class="header-anchor" href="#src-routes-router-ts" aria-label="Permalink to “src/routes/router.ts”">​</a></h3><ul><li>Register routes and connect them to controllers.</li><li>Keep route semantics stable unless the task explicitly requires an API change.</li><li>Keep API metadata synchronized when route capabilities change.</li></ul><h3 id="src-util" tabindex="-1"><code>src/util/</code> <a class="header-anchor" href="#src-util" aria-label="Permalink to “src/util/”">​</a></h3><ul><li>Put cross-module helpers here, such as response wrappers, cookie helpers, request helpers, logging, and color output.</li><li>Prefer existing helpers before adding a new utility.</li></ul><h2 id="adding-an-api" tabindex="-1">Adding an API <a class="header-anchor" href="#adding-an-api" aria-label="Permalink to “Adding an API”">​</a></h2><p>When adding an endpoint, normally update these areas together:</p><ul><li><code>src/services/apis/...</code> for the upstream capability.</li><li><code>src/controllers/...</code> for HTTP controller logic.</li><li><code>src/controllers/index.ts</code> or the relevant export barrel.</li><li><code>src/routes/router.ts</code> for route registration.</li><li><code>src/routes/api-metadata.ts</code> if public API metadata changes.</li><li><code>src/types/</code> when shared public or cross-module types are needed.</li><li><code>docs/api/...</code> and tests when behavior is user-visible.</li></ul>',17)])])}const b=t(o,[["render",i]]);export{p as __pageData,b as default};
